/**
 * Universal property groups - only properties that apply across ALL store types
 *
 * Currently only Color is universal because:
 * 1. Color is relevant for products in any domain (beauty, fashion, furniture, electronics, etc.)
 * 2. Color requires hex codes for proper Shopware display
 * 3. The AI can reuse these predefined colors with correct hex values
 *
 * All other properties are domain-specific and should be AI-generated:
 * - Beauty: Volume, Scent, Skin Type, Hair Type
 * - Fashion: Size, Fabric, Fit, Length
 * - Furniture: Material, Dimensions, Style
 * - Electronics: Storage, Screen Size, Connectivity
 */
export const UNIVERSAL_PROPERTY_GROUPS: CachedPropertyGroup[] = [
    {
        name: "Color",
        slug: "color",
        displayType: "color",
        options: COLOR_OPTIONS.map((c) => c.name),
        colorHexCodes: Object.fromEntries(COLOR_OPTIONS.map((c) => [c.name, c.hex])),
        createdAt: "2025-01-01T00:00:00.000Z",
        source: "fixture",
    },
];

/**
 * Color hex lookup map for quick access
 */
export const COLOR_HEX_MAP: Record<string, string> = Object.fromEntries(
    COLOR_OPTIONS.map((c) => [c.name.toLowerCase(), c.hex])
);

/**
 * Get hex code for a color name (case-insensitive)
 */
export function getColorHexCode(colorName: string): string | undefined {
    return COLOR_HEX_MAP[colorName.toLowerCase()];
}

/**
 * Get all universal property groups
 */
export function getUniversalPropertyGroups(): CachedPropertyGroup[] {
    return UNIVERSAL_PROPERTY_GROUPS;
}
